import java.io.BufferedReader;
import java.io.File;
import java.io.FileReader;
import java.io.IOException;

public class SecurePathTraversalExample {

    private static final String BASE_PATH = "C:/data/";

    public static void readUserFile(String filename) {
        try {
            File file = new File(BASE_PATH + filename);

            if (!file.getCanonicalPath().startsWith(BASE_PATH)) {
                System.out.println("Access denied. Invalid file path.");
                return;
            }

            BufferedReader br = new BufferedReader(new FileReader(file));

            String line;
            while ((line = br.readLine()) != null) {
                System.out.println(line);
            }

            br.close();
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "secretfile.txt";
        readUserFile(userInput);
    }
}

